const now = Date.now();
const TTL = 5 * 60 * 1000;
const staticData = $getWorkflowStaticData('global');
const q = ($json && $json.query) || {};
const userId = q.userId ? String(q.userId) : '';
// Segmentacao: cada fatia tem cache proprio para nao carregar tudo de uma vez.
// segment ausente = 'full' (compat com o agente/consumidores antigos).
const VALID = ['full','reactivation','active','leads','meta'];
let segment = String(q.segment || 'full').toLowerCase();
if (!VALID.includes(segment)) segment = 'full';
const cacheKey = 'snapshot_' + (userId || 'anon') + '_' + segment;
const hit = staticData && staticData[cacheKey] && staticData[cacheKey + '_at'] && (now - staticData[cacheKey + '_at'] < TTL);
return [{ json: { cache_hit: !!hit, cached: hit ? staticData[cacheKey] : null, user_id: userId, segment, cache_key: cacheKey } }];

const row = ($input.first() && $input.first().json && ($input.first().json.row || $input.first().json)) || {};
const role = String(row.role || 'vendedor') || 'vendedor';
const vendor_code = row.vendor_code || null;
function arrLit(a){
  if (!Array.isArray(a) || a.length === 0) return 'NULL';
  return 'ARRAY[' + a.map(s => "'" + String(s).replace(/'/g,"''") + "'").join(',') + ']::TEXT[]';
}
const estados = Array.isArray(row.estados) ? row.estados : null;
const cidades = Array.isArray(row.cidades) ? row.cidades : null;
// --- Segmentacao: decide quais fatias o SQL deve materializar nesta chamada ---
const seg = String(($('Cache check').first().json.segment) || 'full').toLowerCase();
const wantClientes   = (seg === 'full' || seg === 'reactivation' || seg === 'active');
const wantLeads      = (seg === 'full' || seg === 'leads');
const wantMunicipios = (seg === 'full' || seg === 'reactivation' || seg === 'active');
const wantMeta       = (seg === 'full' || seg === 'meta');
let clientes_where = '';
if (seg === 'reactivation') clientes_where = 'm.elegivel_reativacao IS TRUE AND';
else if (seg === 'active')  clientes_where = '(m.elegivel_reativacao IS NOT TRUE) AND';
// Sub-selects do agg pre-montados (CTE nao referenciada nao executa no Postgres).
const agg_clientes   = wantClientes   ? '(SELECT jsonb_agg(to_jsonb(c.*)) FROM clientes c)'   : 'NULL';
const agg_leads      = wantLeads      ? '(SELECT jsonb_agg(to_jsonb(l.*)) FROM leads l)'      : 'NULL';
const agg_municipios = wantMunicipios ? '(SELECT jsonb_agg(to_jsonb(m.*)) FROM municipios m)' : 'NULL';
const agg_top_prod   = wantMeta ? '(SELECT CASE WHEN uid IS NULL THEN NULL ELSE castor_top_products(uid, 20, NULL) END FROM u)' : 'NULL';
const agg_top_grp    = wantMeta ? '(SELECT CASE WHEN uid IS NULL THEN NULL ELSE castor_top_groups(uid, 20) END FROM u)' : 'NULL';
const agg_trend      = wantMeta ? '(SELECT CASE WHEN uid IS NULL THEN NULL ELSE castor_monthly_trend(uid, NULL, 24) END FROM u)' : 'NULL';
const agg_total_cli  = wantMeta ? '(SELECT COUNT(*) FROM cnt)' : 'NULL';
const agg_total_inat = wantMeta ? '(SELECT COUNT(*) FROM cnt WHERE elegivel_reativacao IS TRUE)' : 'NULL';
const agg_total_ativ = wantMeta ? '(SELECT COUNT(*) FROM cnt WHERE elegivel_reativacao IS NOT TRUE)' : 'NULL';
const agg_total_leads = wantMeta ? '(SELECT COUNT(*) FROM leads)' : 'NULL';
return [{ json: { role, vendor_code, estados, cidades, estados_sql: arrLit(estados), cidades_sql: arrLit(cidades), seg, clientes_where, agg_clientes, agg_leads, agg_municipios, agg_top_prod, agg_top_grp, agg_trend, agg_total_cli, agg_total_inat, agg_total_ativ, agg_total_leads } }];

const r = ($input.first() && $input.first().json && ($input.first().json.row || $input.first().json)) || {};
const ctx = $('Cache check').first().json;
const rl  = $('Carry role').first().json;
const snapshot = {
  generated_at: new Date().toISOString(),
  role: rl.role,
  vendor_code: rl.vendor_code,
  totals: { clientes: +(r.total_clientes||0), ativos: +(r.total_ativos||0), inativos: +(r.total_inativos||0), leads: +(r.total_leads||0) },
  clientes:  r.clientes  || [],
  leads:     r.leads     || [],
  municipios:r.municipios || [],
  top_products: (r.top_products && r.top_products.produtos) || [],
  top_groups: (r.top_groups && r.top_groups.grupos) || [],
  sales_trend: (r.sales_trend && r.sales_trend.serie) || []
};
try { const sd = $getWorkflowStaticData('global'); sd[ctx.cache_key] = snapshot; sd[ctx.cache_key + '_at'] = Date.now(); } catch (e) {}
return [{ json: { ok: true, data: snapshot, error: null, cached: false } }];

const body = $json.body || $json;
const out = {
  user_id: String(body.user_id || ''),
  cliente_codigo: String(body.cliente_codigo || '').trim()
};
if (!out.user_id) return [{ json: { ok:false, error:'user_id obrigatorio' } }];
if (!out.cliente_codigo) return [{ json: { ok:false, error:'cliente_codigo obrigatorio' } }];
return [{ json: Object.assign({ ok:true }, out) }];

const r = ($input.first() && $input.first().json && $input.first().json.row) || null;
if (!r) return [{ json: { ok:false, data:null, error:'sem retorno' } }];
if (r.ok === false) return [{ json: { ok:false, data:null, error: r.error || 'erro' } }];
return [{ json: { ok:true, data: r, error:null } }];

const body = $json.body || $json;
const out = {
  user_id: String(body.user_id || ''),
  cliente_codigo: String(body.cliente_codigo || '').trim(),
  endereco: body.endereco ? String(body.endereco) : null,
  cep: body.cep ? String(body.cep) : null,
  municipio: body.municipio ? String(body.municipio) : null,
  uf: body.uf ? String(body.uf) : null,
  contato_nome: body.contato_nome ? String(body.contato_nome) : null,
  contato_tel: body.contato_tel ? String(body.contato_tel) : null,
  contato_email: body.contato_email ? String(body.contato_email) : null,
  contato_whats: body.contato_whats ? String(body.contato_whats) : null,
  notes: body.notes ? String(body.notes) : null,
  lifecycle: body.lifecycle ? String(body.lifecycle) : null
};
if (!out.user_id) return [{ json: { ok:false, error:'user_id obrigatorio' } }];
if (!out.cliente_codigo) return [{ json: { ok:false, error:'cliente_codigo obrigatorio' } }];
if (out.lifecycle && !['ativo','encerrado','nao_interessado_permanente'].includes(out.lifecycle)) return [{ json: { ok:false, error:'lifecycle invalido' } }];
return [{ json: Object.assign({ ok:true }, out) }];

const body = $json.body || $json;
const out = {
  user_id: String(body.user_id || ''),
  cliente_codigo: String(body.cliente_codigo || '').trim(),
  lifecycle: String(body.lifecycle || '').trim(),
  notes: body.notes ? String(body.notes) : null
};
if (!out.user_id) return [{ json: { ok:false, error:'user_id obrigatorio' } }];
if (!out.cliente_codigo) return [{ json: { ok:false, error:'cliente_codigo obrigatorio' } }];
if (!['ativo','encerrado','nao_interessado_permanente'].includes(out.lifecycle)) return [{ json: { ok:false, error:'lifecycle invalido' } }];
return [{ json: Object.assign({ ok:true }, out) }];

const body = $json.body || $json;
const out = {
  user_id: String(body.user_id || ''),
  since_hours: (body.since_hours !== undefined && body.since_hours !== null && body.since_hours !== '') ? +body.since_hours : 48,
  limit: (body.limit !== undefined && body.limit !== null && body.limit !== '') ? +body.limit : 30
};
if (!out.user_id) return [{ json: { ok:false, error:'user_id obrigatorio' } }];
return [{ json: Object.assign({ ok:true }, out) }];

parameters.query:
SELECT COALESCE(jsonb_agg(t), '[]'::jsonb) AS row FROM castor_client_recent_changes(
  '{{ $json.user_id }}'::uuid,
  {{ $json.since_hours }},
  {{ $json.limit }}
) t;
